onChange.script:
if origin == 'BindingWriteback':
	prev_name = previousValue.getValue()['name'].value
	curr_name = currentValue.getValue()['name'].value
	data = self.params.operation
	data = BlueRidge.Recipe.Util.convertWrapperObjectToJson(data)
	data['user']=self.session.props.auth.user.userName
	resp = BlueRidge.Recipe.Operation.update(data)
	if len(resp) > 0:
		if prev_name == curr_name:
			self.custom.triggerRefresh = not self.custom.triggerRefresh
		else:
			system.perspective.sendMessage("refreshTrigger")

customMethods.script:
fileTypes = self.view.custom.fileTypes
defaultParams = self.view.custom.defaultParams
paramLists = self.view.custom.paramLists

if not fileTypes or defaultParams is None:
	return

working = []
for i, fileType in enumerate(fileTypes):
	routineKey = None
	for paramList in (paramLists or []):
		if paramList.get('extensionTypeUUID') == fileType.get('key'):
			routineKey = paramList.get('key')
			break
	dbParams = []
	if routineKey:
		dbParams = BlueRidge.Recipe.HeadParameter.getAll(routineKey)
	if dbParams and len(dbParams) > 0:
		working.append(dbParams)
	elif len(defaultParams) > i:
		working.append(defaultParams[i])
	else:
		working.append([])
self.view.custom.preSaveParams = working

data = self.view.params.operation
data = BlueRidge.Recipe.Util.convertWrapperObjectToJson(data)
data['user'] = self.session.props.auth.user.userName
resp = BlueRidge.Recipe.Operation.update(data)
if resp == -1:
	pass

currentTab = self.view.custom.selectedTab
fileTypes = self.view.custom.fileTypes or []
fileTypeKey = None
if currentTab is not None and len(fileTypes) > currentTab:
	fileTypeKey = fileTypes[currentTab].get('key')
if not fileTypeKey:
	fileTypeKey = self.view.custom.fileTypeKey

selectedData = self.view.custom.selectedData
operationEngine = BlueRidge.Recipe.Util.convertWrapperObjectToJson(self.view.custom.operationEngine) or {}
headOperationUUID = selectedData or operationEngine.get('key')
if not headOperationUUID and selectedData:
	resolvedOp = BlueRidge.Recipe.OperationHead.getOne(selectedData)
	if resolvedOp:
		try:
			resolvedOp = BlueRidge.Recipe.Util.convertWrapperObjectToJson(resolvedOp)
		except:
			pass
		headOperationUUID = resolvedOp.get('key') or resolvedOp.get('headOperationUUID') or resolvedOp.get('operationHeadUUID')

def _get_param_lists():
	results = []
	seen = set()
	queries = []
	if headOperationUUID and self.view.params.operation.key:
		queries.append('%s//%s' % (headOperationUUID, self.view.params.operation.key))
	if headOperationUUID:
		queries.append(headOperationUUID)
	for query in queries:
		try:
			rows = BlueRidge.Recipe.ParameterList.getAll(query) or []
		except:
			rows = []
		for row in rows:
			row = BlueRidge.Recipe.Util.convertWrapperObjectToJson(row)
			rowKey = row.get('key')
			if rowKey not in seen:
				seen.add(rowKey)
				results.append(row)
	return results

routine = BlueRidge.Recipe.Util.convertWrapperObjectToJson(self.view.custom.routine) or {}
routineName = routine.get('name')
if not routineName:
	try:
		routineName = self.view.custom.routine.name
	except:
		pass
if not routineName:
	try:
		routineName = self.view.params.operation.name
	except:
		pass
routineKey = routine.get('key')
currentParamLists = _get_param_lists()
if not routineKey:
	for paramList in currentParamLists:
		if paramList.get('extensionTypeUUID') == fileTypeKey:
			routineKey = paramList.get('key')
			routine = dict(paramList)
			break

if not routineKey and headOperationUUID and fileTypeKey:
	addData = {
		'user': self.session.props.auth.user.userName,
		'typeKey': fileTypeKey,
		'opKey': headOperationUUID
	}
	if routineName:
		addData['name'] = routineName
	addResp = BlueRidge.Recipe.ParameterList.add(addData)
	if addResp == -1:
		pass
	currentParamLists = _get_param_lists()
	for paramList in currentParamLists:
		if paramList.get('extensionTypeUUID') == fileTypeKey:
			routineKey = paramList.get('key')
			routine = dict(paramList)
			break

if routineKey:
	routine['key'] = routineKey
	routine['extensionTypeUUID'] = routine.get('extensionTypeUUID') or fileTypeKey
	routine['engineOperationUUID'] = routine.get('engineOperationUUID') or headOperationUUID
	routine['available'] = self.view.params.operation.available
	routine['verified'] = routine.get('verified', False)
	routine['user'] = self.session.props.auth.user.userName
	if routineName:
		routine['name'] = routineName
	elif not routine.get('name'):
		routine.pop('name', None)
	resp = BlueRidge.Recipe.ParameterList.update(routine)
	if resp == -1:
		pass
	currentParamLists = _get_param_lists()
	for paramList in currentParamLists:
		if paramList.get('extensionTypeUUID') == fileTypeKey:
			routineKey = paramList.get('key') or routineKey
			routine = dict(paramList)
			break

if not routineKey:
	raise ValueError('Unable to determine parameter list key for save. headOperation=%r fileType=%r operation=%r' % (headOperationUUID, fileTypeKey, self.view.params.operation.key))

self.view.custom.paramLists = currentParamLists or self.view.custom.paramLists
self.view.custom.routine = routine

datas = []
if currentTab is not None and self.view.custom.preSaveParams and len(self.view.custom.preSaveParams) > currentTab:
	datas = self.view.custom.preSaveParams[currentTab]
datas = BlueRidge.Recipe.Util.convertWrapperObjectToJson(datas)
for data in datas:
	data = BlueRidge.Recipe.Util.convertWrapperObjectToJson(data)
	data['parameterListUUID'] = routineKey
	data['user'] = self.session.props.auth.user.userName
	resp = BlueRidge.Recipe.HeadParameter.update(data)
	if resp == -1:
		pass

self.view.custom.triggerRefresh = not self.view.custom.triggerRefresh
self.loadWorkingParams()
